class Solution {
public:
    int subarrayGCD(vector<int>& nums, int k) {
        int n = nums.size();
        int total = 0;

        for (int i = 0; i < n; ) {
            if (nums[i] % k != 0) {
                i++;
                continue;
            }

            int j = i;
            while (j < n && nums[j] % k == 0) {
                j++;
            }

            vector<int> segment;
            for (int p = i; p < j; p++) {
                segment.push_back(nums[p] / k);
            }

            int count = 0;
            vector<pair<int, int>> prev_gcds;

            for (int num : segment) {
                vector<pair<int, int>> curr_gcds;
                curr_gcds.push_back({num, 1});

                for (auto& p : prev_gcds) {
                    int g = gcd(p.first, num);
                    bool found = false;
                    for (auto& c : curr_gcds) {
                        if (c.first == g) {
                            c.second += p.second;
                            found = true;
                            break;
                        }
                    }
                    if (!found) {
                        curr_gcds.push_back({g, p.second});
                    }
                }

                for (auto& p : curr_gcds) {
                    if (p.first == 1) {
                        count += p.second;
                    }
                }

                prev_gcds = curr_gcds;
            }

            total += count;
            i = j;
        }

        return total;
    }
};

